816       unsigned DiffOperand = 0;    // The operand that differs.
817       for (unsigned i = 1, e = GEPRHS->getNumOperands(); i != e; ++i)
818         if (GEPLHS->getOperand(i) != GEPRHS->getOperand(i)) {
