2210     if (match(Op0, m_OneUse(m_c_Add(m_Specific(Y), m_Value(X))))) {
2211       Value *USub = Builder.CreateIntrinsic(Intrinsic::usub_sat, Ty, {Y, Z});
2212       return BinaryOperator::CreateAdd(X, USub);
2213     }
2214     if (match(Op0, m_OneUse(m_c_Add(m_Specific(Z), m_Value(X))))) {
2215       Value *USub = Builder.CreateIntrinsic(Intrinsic::usub_sat, Ty, {Z, Y});
2216       return BinaryOperator::CreateAdd(X, USub);
2217     }
2218   }
2219 
2220   // sub Op0, smin((sub nsw Op0, Z), 0) --> smax Op0, Z
2221   // sub Op0, smax((sub nsw Op0, Z), 0) --> smin Op0, Z
2222   if (MinMax->isSigned() && match(Y, m_ZeroInt()) &&
2223       match(X, m_NSWSub(m_Specific(Op0), m_Value(Z)))) {
2224     Intrinsic::ID InvID = getInverseMinMaxIntrinsic(MinMax->getIntrinsicID());
2225     Function *F = Intrinsic::getOrInsertDeclaration(I.getModule(), InvID, Ty);
2226     return CallInst::Create(F, {Op0, Z});
2227   }
2228 
2229   return nullptr;
2230 }
