336 static bool hasNoUnsignedWrap(BinaryOperator &I) {
337   auto *OBO = dyn_cast<OverflowingBinaryOperator>(&I);
338   return OBO && OBO->hasNoUnsignedWrap();
339 }
340 
341 static bool hasNoSignedWrap(BinaryOperator &I) {
342   auto *OBO = dyn_cast<OverflowingBinaryOperator>(&I);
343   return OBO && OBO->hasNoSignedWrap();
344 }
