430 /// This performs a few simplifications for operators that are associative or
431 /// commutative:
432 ///
433 ///  Commutative operators:
434 ///
435 ///  1. Order operands such that they are listed from right (least complex) to
436 ///     left (most complex).  This puts constants before unary operators before
437 ///     binary operators.
438 ///
439 ///  Associative operators:
440 ///
441 ///  2. Transform: "(A op B) op C" ==> "A op (B op C)" if "B op C" simplifies.
442 ///  3. Transform: "A op (B op C)" ==> "(A op B) op C" if "A op B" simplifies.
443 ///
444 ///  Associative and commutative operators:
445 ///
446 ///  4. Transform: "(A op B) op C" ==> "(C op A) op B" if "C op A" simplifies.
447 ///  5. Transform: "A op (B op C)" ==> "B op (C op A)" if "C op A" simplifies.
448 ///  6. Transform: "(A op C1) op (B op C2)" ==> "(A op B) op (C1 op C2)"
449 ///     if C1 and C2 are constants.
450 bool InstCombinerImpl::SimplifyAssociativeOrCommutative(BinaryOperator &I) {
451   Instruction::BinaryOps Opcode = I.getOpcode();
452   bool Changed = false;
453 
454   do {
455     // Order operands such that they are listed from right (least complex) to
456     // left (most complex).  This puts constants before unary operators before
457     // binary operators.
458     if (I.isCommutative() && getComplexity(I.getOperand(0)) <
459         getComplexity(I.getOperand(1)))
460       Changed = !I.swapOperands();
461 
462     if (I.isCommutative()) {
463       if (auto Pair = matchSymmetricPair(I.getOperand(0), I.getOperand(1))) {
464         replaceOperand(I, 0, Pair->first);
465         replaceOperand(I, 1, Pair->second);
466         Changed = true;
467       }
468     }
